import { describe, it, expect } from 'bun:test';
import {
  textToCodePointVector,
  codePointVectorToText,
  textToUtf16Vector,
  utf16VectorToText,
  buildUnicodeLexicon,
  buildUtf16Lexicon,
  teleportUnicodeThroughLexicon,
  teleportUtf16ThroughLexicon,
  inflateUnicodeFromTeleport,
  inflateUtf16FromTeleport,
  buildUnicodeStructuralPacket,
  inflateUnicodeFromStructuralPacket,
  buildUtf16StructuralPacket,
  inflateUtf16FromStructuralPacket,
  runUnicodeTeleportShootout,
} from './unspeech-unicode-teleport';

describe('Unicode teleport via shared lexicon', () => {
  it('round-trips Unicode codepoint vectors', () => {
    const text = 'A🙂Z';
    const vector = textToCodePointVector(text);

    expect(vector[0]).toBe('A'.codePointAt(0));
    expect(vector[1]).toBe('🙂'.codePointAt(0));
    expect(codePointVectorToText(vector)).toBe(text);
  });

  it('teleports direct mode and inflates exactly', async () => {
    const text = 'papa🙂mama';
    const lexicon = buildUnicodeLexicon([text, 'alpha bravo']);

    const packet = await teleportUnicodeThroughLexicon(text, lexicon, {
      mode: 'direct',
      tritonCompression: {
        motifSize: 5,
        useBitwiseFold: false,
      },
    });

    expect(packet.strategy).toBe('direct');
    await expect(inflateUnicodeFromTeleport(packet, lexicon)).resolves.toBe(text);
  });

  it('teleports reordered-direct mode with permutation sidecar', async () => {
    const text = 'cab'.repeat(200);
    const lexicon = buildUnicodeLexicon([text]);
    const packet = await teleportUnicodeThroughLexicon(text, lexicon, {
      mode: 'direct-reordered',
      tritonCompression: {
        motifSize: 5,
        useBitwiseFold: false,
      },
    });

    expect(packet.strategy).toBe('direct-reordered');
    await expect(inflateUnicodeFromTeleport(packet, lexicon)).resolves.toBe(text);
  });

  it('auto-selects residual mode when baseline is close', async () => {
    const baseline = 'alpha bravo charlie';
    const target = 'alpha bravo charlie!';
    const lexicon = buildUnicodeLexicon([baseline, target]);

    const packet = await teleportUnicodeThroughLexicon(target, lexicon, {
      mode: 'auto',
      baselineText: baseline,
      tritonCompression: {
        motifSize: 5,
        useBitwiseFold: false,
      },
    });

    expect(packet.strategy).toBe('residual');
    await expect(
      inflateUnicodeFromTeleport(packet, lexicon, { baselineText: baseline })
    ).resolves.toBe(target);
  });

  it('requires a baseline when inflating residual packets', async () => {
    const baseline = 'seed';
    const target = 'seed!';
    const lexicon = buildUnicodeLexicon([baseline, target]);
    const packet = await teleportUnicodeThroughLexicon(target, lexicon, {
      mode: 'residual',
      baselineText: baseline,
    });

    await expect(inflateUnicodeFromTeleport(packet, lexicon)).rejects.toThrow(
      'baselineText'
    );
  });
});

describe('Unordered structural packets', () => {
  it('collapses sequence into canonical multiset order', () => {
    const text = 'caba';
    const lexicon = buildUnicodeLexicon([text]);
    const packet = buildUnicodeStructuralPacket(text, lexicon);
    const canonical = inflateUnicodeFromStructuralPacket(packet, lexicon);

    expect(packet.strategy).toBe('structural-unordered');
    expect(canonical).toBe('aabc');
  });

  it('can be much smaller than direct telemetry when order is irrelevant', async () => {
    const text = 'a'.repeat(1200);
    const lexicon = buildUnicodeLexicon([text]);
    const structural = buildUnicodeStructuralPacket(text, lexicon);
    const direct = await teleportUnicodeThroughLexicon(text, lexicon, {
      mode: 'direct',
      tritonCompression: {
        motifSize: 5,
        useBitwiseFold: false,
      },
    });

    expect(structural.estimatedPayloadBytes).toBeLessThan(
      direct.estimatedPayloadBytes
    );
  });
});

describe('Teleport shootout', () => {
  it('returns ranked entries with best lossless and best any', async () => {
    const baseline = 'alpha bravo charlie';
    const target = 'alpha bravo charlie!';
    const lexicon = buildUnicodeLexicon([baseline, target]);

    const result = await runUnicodeTeleportShootout(target, lexicon, {
      baselineText: baseline,
      tritonCompression: {
        motifSize: 5,
        useBitwiseFold: false,
      },
    });

    expect(result.entries.length).toBeGreaterThanOrEqual(3);
    expect(result.bestLossless.preservesOrder).toBe(true);
    expect(result.bestAny.estimatedPayloadBytes).toBeLessThanOrEqual(
      result.bestLossless.estimatedPayloadBytes
    );
  });
});

describe('UTF-16 teleport codec', () => {
  it('keeps UTF-16 code-unit view (including surrogate pairs)', () => {
    const text = 'A🙂Z';
    const units = textToUtf16Vector(text);

    expect(units.length).toBe(4);
    expect(utf16VectorToText(units)).toBe(text);
  });

  it('teleports UTF-16 direct mode and inflates exactly', async () => {
    const text = '🙂🙂ab🙂';
    const lexicon = buildUtf16Lexicon([text, 'ab']);
    const packet = await teleportUtf16ThroughLexicon(text, lexicon, {
      mode: 'direct',
      tritonCompression: {
        motifSize: 5,
        useBitwiseFold: false,
      },
    });

    expect(packet.strategy).toBe('direct');
    await expect(inflateUtf16FromTeleport(packet, lexicon)).resolves.toBe(text);
  });

  it('teleports UTF-16 residual mode against baseline', async () => {
    const baseline = '🙂a🙂a🙂a';
    const target = '🙂a🙂b🙂a';
    const lexicon = buildUtf16Lexicon([baseline, target]);
    const packet = await teleportUtf16ThroughLexicon(target, lexicon, {
      mode: 'residual',
      baselineText: baseline,
      tritonCompression: {
        motifSize: 5,
        useBitwiseFold: false,
      },
    });

    expect(packet.strategy).toBe('residual');
    await expect(
      inflateUtf16FromTeleport(packet, lexicon, { baselineText: baseline })
    ).resolves.toBe(target);
  });

  it('supports unordered UTF-16 structural collapse', () => {
    const text = '🙂a🙂b';
    const lexicon = buildUtf16Lexicon([text]);
    const packet = buildUtf16StructuralPacket(text, lexicon);
    const canonical = inflateUtf16FromStructuralPacket(packet, lexicon);

    expect(packet.strategy).toBe('structural-unordered');
    expect(textToUtf16Vector(canonical).sort((a, b) => a - b)).toEqual(
      textToUtf16Vector(text).sort((a, b) => a - b)
    );
  });
});
